### Proposed technical implementation details (optional)

Take a more general approach to straighten the old break change that involve cmdlets which the `-Encoding`  parameter by implementing an Encoding convertor. 

### Prototype

```PowerShell
class EncodingConvertor : System.Management.Automation.PSTypeConverter {
    [bool] CanConvertFrom([object]$sourceValue, [type]$destinationType) {
        return $sourceValue -is [int] -or $sourceValue -is [string]
    }

    [object] ConvertFrom([object]$sourceValue, [type]$destinationType, [IFormatProvider]$formatProvider, [bool]$ignoreCase) {
        if ($sourceValue -is [string]) {
            switch ($sourceValue) {
                'ansi'           { return [System.Text.Encoding]::default }
                'bigendianutf32' { return [System.Text.Encoding]::GetEncoding('utf-32BE') }
                'oem'            {
                        $OEMCP = try { Get-ItemPropertyValue HKLM:\SYSTEM\CurrentControlSet\Control\Nls\CodePage OEMCP } catch { $null }
                        if ($OEMCP) { return [System.Text.Encoding]::GetEncoding($OEMCP) }
                        else { return [System.Text.Encoding]::default }
                    }
                'utf8BOM'         { return [System.Text.UTF8Encoding]::new($true) }
                'utf8NoBOM'       { return [System.Text.UTF8Encoding]::new($false) }
            }
            Get-ItemPropertyValue HKLM:\SYSTEM\CurrentControlSet\Control\Nls\CodePage OEMCP
            $property = [System.Text.Encoding].GetProperty(
                $sourceValue,
                [System.Reflection.BindingFlags]::IgnoreCase -bor
                [System.Reflection.BindingFlags]::Public -bor
                [System.Reflection.BindingFlags]::Static,
                $null,
                [System.Text.Encoding],
                [Type[]]@(),
                $null
            )
            if ($property) { return $Property.GetValue([System.Text.Encoding]) }
        }
        $encoding = try { [System.Text.Encoding]::GetEncoding($sourceValue) } catch { throw $_ }
        if ($encoding) { return $encoding }
        throw [ArgumentException]::new("'$sourceValue' is not a supported encoding name. For information on defining a custom encoding, see the documentation for the Encoding.RegisterProvider method.")
    }

    [bool] CanConvertTo([object]$sourceValue, [Type]$destinationType) {
        return $false
    }

    [object] ConvertTo([object]$sourceValue, [Type]$destinationType, [IFormatProvider]$formatProvider, [bool]$ignoreCase) {
        return [NotImplementedException]::new()
    }
}

Update-TypeData -TypeName System.Text.Encoding -TypeConverter EncodingConvertor
```

### Testing

```powershell
BeforeAll {
    Function InvokeOutFile {
        Write-Output "Hello World" | Out-File -Encoding utf8 -FilePath pathToFile
    }
}

Describe "Out-File encoding" {

    Context "Mocking" {
        It "InvokeOutFile" {
            Mock Out-File { 'Mocked' }
            InvokeOutFile | Should -be Mocked
        }
    }

    Context "Parameters" {
        It "ascii: Uses the encoding for the ASCII (7-bit) character set." {
            [System.Text.Encoding]'ascii' | Should -be ([System.Text.Encoding]::ascii)
        }

        It "ansi: Uses the encoding for the for the current culture's ANSI code page. This option was added in PowerShell 7.4." {
            [System.Text.Encoding]'ansi' | Should -be ([System.Text.Encoding]::default)
        }

        It "bigendianunicode: Encodes in UTF-16 format using the big-endian byte order." {
            [System.Text.Encoding]'bigendianunicode' | Should -be ([System.Text.Encoding]::bigendianunicode)
        }

        It "bigendianutf32: Encodes in UTF-32 format using the big-endian byte order." {
            [System.Text.Encoding]'bigendianutf32' | Should -be ([System.Text.Encoding]::GetEncoding('utf-32BE'))
        }

        It "oem: Uses the default encoding for MS-DOS and console programs." {
            [System.Text.Encoding]'oem' | Should -be ([System.Text.Encoding]::GetEncoding(437))
        }

        It "unicode: Encodes in UTF-16 format using the little-endian byte order." {
            [System.Text.Encoding]'unicode' | Should -be ([System.Text.Encoding]::unicode)
        }

        It "utf7: Encodes in UTF-7 format." {
            [System.Text.Encoding]'utf7' | Should -be ([System.Text.Encoding]::utf7)
        }

        It "utf8: Encodes in UTF-8 format." {
            [System.Text.Encoding]'utf8' | Should -be ([System.Text.Encoding]::utf8)
        }

        It "'utf8BOM': Encodes in UTF-8 format with Byte Order Mark (BOM)" {
            [System.Text.Encoding]'utf8BOM' | Should -be ([System.Text.UTF8Encoding]::new($true))
        }

        It "utf8NoBOM: Encodes in UTF-8 format without Byte Order Mark (BOM)" {
            [System.Text.Encoding]'utf8NoBOM' | Should -be ([System.Text.UTF8Encoding]::new($false))
        }

        It "utf32: Encodes in UTF-32 format." {
            [System.Text.Encoding]'utf32' | Should -be ([System.Text.Encoding]::utf32)
        }

    }
}
```
